/** Normalize a LEX item title the same way the fixture keys are normalized. */
export function normalizeItemTitle(title: string): string {
  return title.trim().toLowerCase();
}

/** Look up XP awards for a LEX item by title. Returns {} when unlisted. */
export function lookupItemXp(title: string): Record<string, number> {
  const entry = DA_LEX_ITEM_XP[normalizeItemTitle(title)];
  return entry ? entry.awards : {};
}

/**
 * Map an expression-level XP award payload onto group keys.
 * An expression can belong to multiple groups, so XP contributes to every
 * group that owns the expression.
 */
export function expressionXpToGroupXp(
  awards: Record<string, number>,
  groupsIndex: Record<string, MasteryGroupDef>,
): Record<string, number> {
  const result: Record<string, number> = {};
  for (const [expressionId, xp] of Object.entries(awards)) {
    for (const group of Object.values(groupsIndex)) {
      if (group.expressions.some((e) => e.id === expressionId)) {
        result[group.key] = (result[group.key] ?? 0) + xp;
      }
    }
  }
  return result;
}
